import{_ as e,o as s,c as i,a6 as n,g2 as l}from"./chunks/framework.UYVGz2W_.js";const b=JSON.parse('{"title":"カスタムアクション","description":"","frontmatter":{},"headers":[],"relativePath":"ja/custom-actions/index.md","filePath":"ja/custom-actions/index.md"}'),t={name:"ja/custom-actions/index.md"};function p(r,a,o,c,d,h){return s(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="カスタムアクション" tabindex="-1">カスタムアクション <a class="header-anchor" href="#カスタムアクション" aria-label="Permalink to “カスタムアクション”">​</a></h1><h2 id="カスタムアクションとは" tabindex="-1">カスタムアクションとは？ <a class="header-anchor" href="#カスタムアクションとは" aria-label="Permalink to “カスタムアクションとは？”">​</a></h2><p>カスタムアクションとは、現在選択されているKitsuの情報をカスタムエンドポイントに送信するシンプルなHTTPリクエストです。 基本的に、ユーザーがKitsuのUIにいる場合、選択された要素のIDを含むリクエストを別のサーバーに送信することができます。</p><h3 id="目的" tabindex="-1">目的 <a class="header-anchor" href="#目的" aria-label="Permalink to “目的”">​</a></h3><p>目標は、Kitsu/Zouのコアコードを変更することなく、Kitsu以外のアクションを作成することです（プラグインシステムが利用可能になるまで）。基本的には、ご自身で管理するページやサービスへのウェブリクエスト、通常はPOST（GETも可能）です。リクエストをキャッチし、それを使ってアクションを実行します。</p><p>例としては、</p><ul><li>デバッグページ（フィールド名など、指定のオブジェクトのアクセス可能な情報をすべて表示する）</li><li>CGRUまたはFlamencoでレンダリングを起動する</li><li>APM用の統計ページを生成する</li><li>特別なプレイリストを作成する</li><li>カスタムプロトコル（サービスが待機）を起動して、ビデオプレーヤー、DCCなどを開始する</li><li>Kabaretなどのアセットマネージャーと統合して、適切な場所でアセットを開いたり、アクションを起動する</li></ul><p>カスタムアクションは、リクエストをキャッチできるものであれば何でも可能です（例えば、Flask や Tornado.web などの Python ウェブサーバーを使用）。 カスタムアクションは、あなたが管理するシステムに Kitsu を拡張するために設計されています。</p><p>現在の選択、閲覧中のページ、アクションを起動したユーザーなど、リクエストをキャッチしたものには、便利な情報が提供されます。提供された情報に基づいて応答を適応させることができます。</p><p>ユーザーにフィードバックを提供する必要がない場合は、カスタムアクションをバックグラウンドで実行することもできます（新しいページを開く代わりにAJAXリクエストを使用）。</p><h2 id="カスタムアクションの設定方法" tabindex="-1">カスタムアクションの設定方法 <a class="header-anchor" href="#カスタムアクションの設定方法" aria-label="Permalink to “カスタムアクションの設定方法”">​</a></h2><h3 id="作成" tabindex="-1">作成 <a class="header-anchor" href="#作成" aria-label="Permalink to “作成”">​</a></h3><p>カスタムアクションの設定は、スタジオマネージャーのみが行うことができます。 カスタムアクションページは、管理セクションの右パネルで利用できます。</p><p>カスタムアクションページにアクセスできる場合、右上にある追加ボタンから新しいアクションを作成できます。 アクションの作成には、以下の4つの情報が必要です。</p><p><img src="'+l+`" alt="Add Custom Action"></p><ul><li><strong>名前</strong>：アクションの名前。</li><li><strong>URL</strong>：ターゲットURL（Kitsuのインストールと同じドメインを使用することを強くお勧めします）。</li><li><strong>エンティティタイプ</strong>：カスタムアクションが利用可能なエンティティの種類。</li><li><strong>AJAXを使用</strong>：リクエストをAJAXリクエストとして送信する必要があるか、フォームとして送信する必要があるかを指定します。</li></ul><p>アクションが作成されると、アクションのトップバーからアクセスできるようになります。ユーザーがアセットまたはショットリストでタスクを選択し、「<strong>カスタムアクションの実行</strong>」セクションに移動すると、現在の選択に対してカスタムアクションを実行できるようになります。</p><h3 id="カスタムアクション経由で送信されるデータ" tabindex="-1">カスタムアクション経由で送信されるデータ <a class="header-anchor" href="#カスタムアクション経由で送信されるデータ" aria-label="Permalink to “カスタムアクション経由で送信されるデータ”">​</a></h3><p>データはJSON形式で送信されます。データには、以下のフィールドを持つオブジェクトが含まれます。</p><ul><li><code>personid</code>：アクションを要求するユーザーのID。</li><li><code>personemail</code>: アクションを要求するユーザーのメールアドレス。</li><li><code>projectid</code>: 選択されたエンティティのプロジェクトID。</li><li><code>currentpath</code>: Kitsuウェブアプリケーションの現在のURLパス。</li><li><code>currentserver</code>: カスタムアクションを送信するKitsuのホスト。</li><li><code>selection</code>: 選択されたタスクIDのリスト。</li><li><code>entitytype</code>: タスクが選択されたエンティティの種類。</li></ul><p>例：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>{</span></span>
<span class="line"><span>「personid「: 」b01bae1e-f829-458a-a1eb-131bb66628cc「,</span></span>
<span class="line"><span>「personemail」: 「admin@example.com」,</span></span>
<span class="line"><span>「projectid「: 」fa4d7f04-b8e0-4518-8dbc-2f24997ca76e」,</span></span>
<span class="line"><span>「currentpath「: 」/productions/fa4d7f04-b8e0-4518-8dbc-2f24997ca76e/assets「,</span></span>
<span class="line"><span>「currentserver」: 「localhost」,</span></span>
<span class="line"><span>「selection「: 」95c171e1-dfff-498f-93e3-548a739e3202」,</span></span>
<span class="line"><span>「entitytype「: 」asset」</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,22)])])}const f=e(t,[["render",p]]);export{b as __pageData,f as default};
